#!/usr/bin/env python3
from pathlib import Path
from datetime import datetime
import json, subprocess, sys
APP = Path("apps/pfotentechnik")
ENGINE = APP / "src/domain/recommendationLinks.ts"
SLUG = APP / "src/pages/[slug].astro"
MANUFACTURER = APP / "src/pages/hersteller/[manufacturer].astro"
PACKAGE = APP / "package.json"
AUDIT = Path("scripts/audit-recommendation-engine-4.mjs")
ENGINE_CONTENT = "export type RecommendationEntry = { data: Record<string, any> };\nexport type RecommendationLink = { eyebrow: string; title: string; text: string; href: string; label: string };\n\ntype Topic = \"feeder\" | \"fountain\" | \"gps\" | \"cat-flap\" | \"litter-box\" | \"health\" | \"nutrition\";\ntype Context = {\n  animal?: \"dog\" | \"cat\";\n  petSize?: \"small\" | \"medium\" | \"large\";\n  topic?: Topic;\n  tokens: Set<string>;\n};\n\nconst normalize = (value: unknown) =>\n  String(value ?? \"\").toLowerCase()\n    .replace(/ä/g, \"ae\").replace(/ö/g, \"oe\").replace(/ü/g, \"ue\").replace(/ß/g, \"ss\")\n    .replace(/[^a-z0-9]+/g, \" \").trim();\n\nconst asArray = (value: unknown): unknown[] =>\n  Array.isArray(value) ? value : value == null ? [] : [value];\n\nconst collectText = (data: Record<string, any>) =>\n  normalize([\n    data.slug, data.title, data.name, data.description, data.summary,\n    data.recommendation, data.category, data.categoryLabel, data.linkContext,\n    data.contentPlatform?.cluster, data.contentPlatform?.intent,\n    data.manufacturer?.name, data.manufacturer?.slug,\n    ...asArray(data.tags), ...asArray(data.features), ...asArray(data.useCase),\n    ...asArray(data.productCategories), ...asArray(data.linking?.contexts),\n    ...asArray(data.linking?.keywords), ...asArray(data.comparisonFilters?.foodType),\n    ...asArray(data.comparisonFilters?.features)\n  ].filter(Boolean).join(\" \"));\n\nconst detectAnimal = (data: Record<string, any>, text: string) => {\n  const explicit = data.recommendationJourney?.animal ?? data.contentPlatform?.animal;\n  if (explicit === \"dog\" || explicit === \"cat\") return explicit;\n  const filters = asArray(data.comparisonFilters?.animal);\n  if (filters.length === 1 && (filters[0] === \"dog\" || filters[0] === \"cat\")) return filters[0];\n  const dog = /\\b(hund|hunde|dog|dogs)\\b/.test(text);\n  const cat = /\\b(katze|katzen|cat|cats)\\b/.test(text);\n  if (dog && !cat) return \"dog\";\n  if (cat && !dog) return \"cat\";\n  return undefined;\n};\n\nconst detectPetSize = (data: Record<string, any>, text: string) => {\n  const explicit = data.recommendationJourney?.petSize;\n  if ([\"small\", \"medium\", \"large\"].includes(explicit)) return explicit;\n  const filters = asArray(data.comparisonFilters?.petSize);\n  if (filters.length === 1 && [\"small\", \"medium\", \"large\"].includes(String(filters[0]))) {\n    return filters[0] as \"small\" | \"medium\" | \"large\";\n  }\n  if (/\\b(gross|grosse|grosser|large)\\b/.test(text)) return \"large\";\n  if (/\\b(mittel|mittelgross|medium)\\b/.test(text)) return \"medium\";\n  if (/\\b(klein|kleine|kleiner|small)\\b/.test(text)) return \"small\";\n  return undefined;\n};\n\nconst detectTopic = (text: string): Topic | undefined => {\n  if (/\\b(gps|tracker|ortung|halsband)\\b/.test(text)) return \"gps\";\n  if (/\\b(trinkbrunnen|wasserbrunnen|fountain)\\b/.test(text)) return \"fountain\";\n  if (/\\b(katzenklappe|cat flap|microchip flap)\\b/.test(text)) return \"cat-flap\";\n  if (/\\b(katzentoilette|litter box|selbstreinigend)\\b/.test(text)) return \"litter-box\";\n  if (/\\b(futterautomat|futterautomaten|feeder|fuetterungsroboter)\\b/.test(text)) return \"feeder\";\n  if (/\\b(futter|ernaehrung|kalorien|nassfutter|trockenfutter)\\b/.test(text)) return \"nutrition\";\n  if (/\\b(tierarzt|durchfall|erbrechen|mued|frisst nicht|trinkt)\\b/.test(text)) return \"health\";\n  return undefined;\n};\n\nconst buildContext = (data: Record<string, any>): Context => {\n  const text = collectText(data);\n  return {\n    animal: detectAnimal(data, text),\n    petSize: detectPetSize(data, text),\n    topic: detectTopic(text),\n    tokens: new Set(text.split(/\\s+/).filter((token) => token.length >= 4))\n  };\n};\n\nconst overlap = (a: Set<string>, b: Set<string>) => {\n  let score = 0;\n  for (const token of a) if (b.has(token)) score += 1;\n  return Math.min(score, 8);\n};\n\nconst scoreContext = (source: Context, candidate: Context) => {\n  let score = overlap(source.tokens, candidate.tokens);\n  if (source.topic && candidate.topic) score += source.topic === candidate.topic ? 18 : -24;\n  if (source.animal && candidate.animal) score += source.animal === candidate.animal ? 10 : -16;\n  if (source.petSize && candidate.petSize) score += source.petSize === candidate.petSize ? 7 : -7;\n  return score;\n};\n\nconst isMoneyGuide = (data: Record<string, any>) => {\n  const intent = data.contentPlatform?.intent;\n  return data.recommendationJourney?.mode === \"filtered\" ||\n    intent === \"buying-guide\" ||\n    intent === \"comparison-support\" ||\n    /\\b(kaufberatung|welcher|beste|passende)\\b/.test(collectText(data));\n};\n\nconst rank = <T extends RecommendationEntry>(\n  source: Record<string, any>,\n  candidates: T[],\n  extra: (entry: T) => number = () => 0\n) => {\n  const sourceContext = buildContext(source);\n  return candidates\n    .map((entry) => ({ entry, score: scoreContext(sourceContext, buildContext(entry.data)) + extra(entry) }))\n    .filter(({ score }) => score > 0)\n    .sort((a, b) => b.score - a.score || normalize(a.entry.data.slug).localeCompare(normalize(b.entry.data.slug)));\n};\n\nexport const getBestMoneyGuide = (\n  source: Record<string, any>, pages: RecommendationEntry[], currentSlug?: string\n) => rank(\n  source,\n  pages.filter((entry) => entry.data.slug !== currentSlug && isMoneyGuide(entry.data)),\n  (entry) =>\n    (entry.data.recommendationJourney?.mode === \"filtered\" ? 7 : 0) +\n    (entry.data.contentPlatform?.intent === \"buying-guide\" ? 5 : 0) +\n    Math.min(Number(entry.data.hubPriority ?? 0) / 20, 4)\n)[0]?.entry;\n\nexport const getBestComparison = (\n  source: Record<string, any>, comparisons: RecommendationEntry[]\n) => rank(\n  source,\n  comparisons,\n  (entry) => (/\\bbeste\\b/.test(collectText(entry.data)) ? 4 : 0) +\n    (/\\bvergleich\\b/.test(collectText(entry.data)) ? 2 : 0)\n)[0]?.entry;\n\nexport const getBestProduct = (\n  source: Record<string, any>, products: RecommendationEntry[]\n) => rank(\n  source,\n  products.filter((entry) => ![\"discontinued\", \"legacy\"].includes(entry.data.productStatus)),\n  (entry) => Math.min(Number(entry.data.score ?? 0) / 15, 7) + Math.min(Number(entry.data.rating ?? 0), 5)\n)[0]?.entry;\n\nconst productLink = (entry: RecommendationEntry): RecommendationLink => ({\n  eyebrow: \"Top-Empfehlung\", title: entry.data.title,\n  text: entry.data.recommendation ?? \"Öffne die vollständige redaktionelle Einordnung dieses Modells.\",\n  href: `/produkt/${entry.data.slug}/`, label: \"Produkt ansehen\"\n});\nconst comparisonLink = (entry: RecommendationEntry): RecommendationLink => ({\n  eyebrow: \"Vergleich\", title: entry.data.title,\n  text: entry.data.description ?? \"Vergleiche passende Modelle direkt miteinander.\",\n  href: `/vergleiche/${entry.data.slug}/`, label: \"Zum Vergleich\"\n});\nconst guideLink = (entry: RecommendationEntry): RecommendationLink => ({\n  eyebrow: \"Kaufberatung\", title: entry.data.title,\n  text: entry.data.description ?? \"Ordne die wichtigsten Anforderungen vor der Auswahl genauer ein.\",\n  href: `/${entry.data.slug}/`, label: \"Kaufberatung lesen\"\n});\n\nexport const buildMoneyPageNextSteps = ({ page, comparisons, products }: {\n  page: Record<string, any>; comparisons: RecommendationEntry[]; products: RecommendationEntry[];\n}): RecommendationLink[] => {\n  const product = getBestProduct(page, products);\n  const comparison = getBestComparison(page, comparisons);\n  return [...(product ? [productLink(product)] : []), ...(comparison ? [comparisonLink(comparison)] : [])].slice(0, 2);\n};\n\nexport const buildComparisonNextSteps = ({ comparison, pages, products }: {\n  comparison: Record<string, any>; pages: RecommendationEntry[]; products: RecommendationEntry[];\n}): RecommendationLink[] => {\n  const guide = getBestMoneyGuide(comparison, pages);\n  const product = getBestProduct(comparison, products);\n  return [...(guide ? [guideLink(guide)] : []), ...(product ? [productLink(product)] : [])].slice(0, 2);\n};\n\nexport const buildProductNextSteps = ({ product, pages, comparisons }: {\n  product: Record<string, any>; pages: RecommendationEntry[]; comparisons: RecommendationEntry[];\n}): RecommendationLink[] => {\n  const comparison = getBestComparison(product, comparisons);\n  const guide = getBestMoneyGuide(product, pages);\n  return [...(comparison ? [comparisonLink(comparison)] : []), ...(guide ? [guideLink(guide)] : [])].slice(0, 2);\n};\n\nexport const buildManufacturerNextSteps = ({ manufacturer, pages, comparisons, products }: {\n  manufacturer: Record<string, any>; pages: RecommendationEntry[];\n  comparisons: RecommendationEntry[]; products: RecommendationEntry[];\n}): RecommendationLink[] => {\n  const ownProducts = products.filter((entry) =>\n    entry.data.manufacturer?.slug === manufacturer.slug ||\n    entry.data.manufacturer?.key === manufacturer.key ||\n    asArray(manufacturer.productSlugs).includes(entry.data.slug)\n  );\n  const source = {\n    ...manufacturer,\n    tags: [...asArray(manufacturer.tags), ...ownProducts.flatMap((entry) => asArray(entry.data.tags))],\n    features: ownProducts.flatMap((entry) => asArray(entry.data.features))\n  };\n  const comparison = getBestComparison(source, comparisons);\n  const guide = getBestMoneyGuide(source, pages);\n  return [...(comparison ? [comparisonLink(comparison)] : []), ...(guide ? [guideLink(guide)] : [])].slice(0, 2);\n};\n"
AUDIT_CONTENT = "import fs from \"node:fs\";\nimport path from \"node:path\";\n\nconst appRoot = path.resolve(\"apps/pfotentechnik\");\nconst checks = [\n  [\"src/domain/recommendationLinks.ts\", \"buildManufacturerNextSteps\"],\n  [\"src/pages/[slug].astro\", \"buildMoneyPageNextSteps\"],\n  [\"src/pages/produkt/[product].astro\", \"buildProductNextSteps\"],\n  [\"src/pages/vergleiche/[comparison].astro\", \"buildComparisonNextSteps\"],\n  [\"src/pages/hersteller/[manufacturer].astro\", \"buildManufacturerNextSteps\"]\n];\n\nconst problems = [];\nfor (const [relative, marker] of checks) {\n  const full = path.join(appRoot, relative);\n  if (!fs.existsSync(full)) {\n    problems.push(`Fehlende Datei: ${relative}`);\n    continue;\n  }\n  const text = fs.readFileSync(full, \"utf8\");\n  if (!text.includes(marker)) problems.push(`${relative}: ${marker} fehlt`);\n}\n\nif (problems.length) {\n  console.error(\"Recommendation Engine 4.0 Audit fehlgeschlagen:\");\n  problems.forEach((problem) => console.error(`- ${problem}`));\n  process.exit(1);\n}\nconsole.log(\"Recommendation Engine 4.0 Audit erfolgreich.\");\n"
def stop(message):
    print(f"FEHLER: {message}", file=sys.stderr)
    raise SystemExit(1)
def find_root(start):
    for candidate in (start, *start.parents):
        if (candidate / APP / "package.json").is_file(): return candidate
    stop("Repository-Root nicht gefunden.")
def replace_once(text, old, new, label):
    count = text.count(old)
    if count != 1: stop(f"{label}: genau 1 Fundstelle erwartet, gefunden: {count}")
    return text.replace(old, new, 1)
def run(command, cwd):
    print("$", " ".join(command))
    if subprocess.run(command, cwd=cwd).returncode != 0:
        raise RuntimeError("Befehl fehlgeschlagen: " + " ".join(command))
root = find_root(Path.cwd().resolve())
required = [ENGINE, SLUG, MANUFACTURER, PACKAGE]
for relative in required:
    if not (root / relative).is_file(): stop(f"Erforderliche Datei fehlt: {relative}")
originals = {relative: (root / relative).read_bytes() for relative in required}
audit_existed = (root / AUDIT).exists()
audit_original = (root / AUDIT).read_bytes() if audit_existed else None
slug = originals[SLUG].decode("utf-8")
manufacturer = originals[MANUFACTURER].decode("utf-8")
package = originals[PACKAGE].decode("utf-8")
if "buildMoneyPageNextSteps" in slug: stop("Recommendation Engine 4.0 scheint bereits installiert zu sein.")
slug = replace_once(slug, "import ConversionJourney from \"../components/ConversionJourney.astro\";", "import ConversionJourney from \"../components/ConversionJourney.astro\";\nimport DecisionNextSteps from \"../components/DecisionNextSteps.astro\";", "Money-Page Komponentenimport")
slug = replace_once(slug, "import {\n  getInternalLinkDefinitions,\n  getSourceContexts\n} from \"../domain/content/internalLinks\";", "import {\n  getInternalLinkDefinitions,\n  getSourceContexts\n} from \"../domain/content/internalLinks\";\nimport { buildMoneyPageNextSteps } from \"../domain/recommendationLinks\";", "Money-Page Engine-Import")
slug = replace_once(slug, "const closingProduct = assembledPage.closingCta\n  ? productBySlug.get(assembledPage.closingCta.productKey)\n  : undefined;", "const closingProduct = assembledPage.closingCta\n  ? productBySlug.get(assembledPage.closingCta.productKey)\n  : undefined;\n\nconst moneyPageNextSteps = isMoneyPage\n  ? buildMoneyPageNextSteps({\n      page: page.data,\n      comparisons,\n      products\n    })\n  : [];", "Money-Page Empfehlungen")
start = slug.find("    {\n      recommendationJourney && (\n        <section class=\"recommendation-journey-state\">")
end = slug.find("    {\n      decisionRule?.sources", start)
if start == -1 or end == -1: stop("Recommendation-Block nach dem Hauptinhalt nicht gefunden.")
replacement = "    {\n      isMoneyPage && moneyPageNextSteps.length > 0 && (\n        <DecisionNextSteps\n          title=\"Passend weiterentscheiden\"\n          intro=\"Öffne die stärkste passende Produktempfehlung oder den zugehörigen Vergleich.\"\n          items={moneyPageNextSteps}\n        />\n      )\n    }\n\n"
slug = slug[:start] + replacement + slug[end:]
manufacturer = replace_once(manufacturer, "import RelatedArticles from \"@affiliate-core/components/RelatedArticles.astro\";", "import RelatedArticles from \"@affiliate-core/components/RelatedArticles.astro\";\nimport DecisionNextSteps from \"../../components/DecisionNextSteps.astro\";", "Hersteller Komponentenimport")
manufacturer = replace_once(manufacturer, "import {\n  getManufacturerBreadcrumbs,\n  getRelatedContent\n} from \"@app/domain/content\";", "import {\n  getManufacturerBreadcrumbs,\n  getRelatedContent\n} from \"@app/domain/content\";\nimport { buildManufacturerNextSteps } from \"../../domain/recommendationLinks\";", "Hersteller Engine-Import")
manufacturer = replace_once(manufacturer, "const allProducts = await getCollection(\"products\");\nconst allManufacturers = await getCollection(\"manufacturers\");", "const [allProducts, allManufacturers, pages, comparisons] = await Promise.all([\n  getCollection(\"products\"),\n  getCollection(\"manufacturers\"),\n  getCollection(\"pages\"),\n  getCollection(\"comparisons\")\n]);", "Hersteller Collections")
manufacturer = replace_once(manufacturer, "const productHref = (slug: string, productUrl?: string) =>\n  productUrl ?? `/produkt/${slug}/`;", "const productHref = (slug: string, productUrl?: string) =>\n  productUrl ?? `/produkt/${slug}/`;\n\nconst manufacturerNextSteps = buildManufacturerNextSteps({\n  manufacturer,\n  pages,\n  comparisons,\n  products: allProducts\n});", "Hersteller Empfehlungen")
manufacturer = replace_once(manufacturer, "    <RelatedArticles items={relatedItems} />", "    <DecisionNextSteps\n      title=\"Marke sinnvoll einordnen\"\n      intro=\"Vergleiche die Produktklasse oder öffne die passende Kaufberatung.\"\n      items={manufacturerNextSteps}\n    />\n\n    <RelatedArticles items={relatedItems} />", "Hersteller Ausgabe")
package_data = json.loads(package)
package_data.setdefault("scripts", {})["audit:recommendations"] = "node ../../scripts/audit-recommendation-engine-4.mjs"
package = json.dumps(package_data, ensure_ascii=False, indent=2) + "\n"
prepared = {ENGINE: ENGINE_CONTENT.encode(), SLUG: slug.encode(), MANUFACTURER: manufacturer.encode(), PACKAGE: package.encode(), AUDIT: AUDIT_CONTENT.encode()}
stamp = datetime.now().strftime("%Y-%m-%dT%H-%M-%S")
backup = root / f".recommendation-engine-4.0-backup-{stamp}"
backup.mkdir(parents=True, exist_ok=False)
for relative, data in originals.items():
    dest = backup / relative; dest.parent.mkdir(parents=True, exist_ok=True); dest.write_bytes(data)
if audit_existed:
    dest = backup / AUDIT; dest.parent.mkdir(parents=True, exist_ok=True); dest.write_bytes(audit_original)
try:
    for relative, data in prepared.items():
        dest = root / relative; dest.parent.mkdir(parents=True, exist_ok=True); dest.write_bytes(data)
    run(["npm", "run", "build:pfotentechnik"], root)
    run(["npm", "--workspace", "apps/pfotentechnik", "run", "audit:recommendations"], root)
    if "\"audit:repository\"" in package:
        run(["npm", "--workspace", "apps/pfotentechnik", "run", "audit:repository"], root)
except Exception as exc:
    print(f"Validierung fehlgeschlagen: {exc}", file=sys.stderr)
    print("Automatischer Rollback wird ausgeführt.", file=sys.stderr)
    for relative, data in originals.items():
        dest = root / relative; dest.parent.mkdir(parents=True, exist_ok=True); dest.write_bytes(data)
    audit_path = root / AUDIT
    if audit_existed: audit_path.write_bytes(audit_original)
    elif audit_path.exists(): audit_path.unlink()
    raise SystemExit(1)
print("Recommendation Engine 4.0 erfolgreich installiert.")
print(f"Backup: {backup}")
